interface SessionStore {
    String newSessionId();
    void save(AuthenticatedSession session);
    AuthenticatedSession get(String sessionId);
    void invalidate(String sessionId);
}

class InMemorySessionStore implements SessionStore {
    private final Map<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();

    @Override
    public String newSessionId() {
        long r = ThreadLocalRandom.current().nextLong();
        return "saml-" + Long.toUnsignedString(r, 16) + "-" + System.nanoTime();
    }

    @Override
    public void save(AuthenticatedSession session) {
        sessions.put(session.getSessionId(), session);
    }

    @Override
    public AuthenticatedSession get(String sessionId) {
        return sessions.get(sessionId);
    }

    @Override
    public void invalidate(String sessionId) {
        sessions.remove(sessionId);
    }
}

class SamlProcessingException extends Exception {
    public SamlProcessingException(String message) { super(message); }
    public SamlProcessingException(String message, Throwable cause) { super(message, cause); }
}